    "source": "{\n  \"kind\": \"design-ai-implementation-scope-request\",\n  \"schemaVersion\": 1,\n  \"objective\": \"Help first-time users understand design-ai and reach a verified install or quickstart path from the documentation homepage first viewport.\",\n  \"intendedBehavior\": [\n    \"Replace the dense README opening with a concise product promise, primary quickstart action, secondary install action, and bounded proof points in English and Korean.\",\n    \"Keep detailed distribution evidence available through the existing external status document without placing the full release record in the first viewport.\",\n    \"Give the Material navigation and search toggles programmatic names without changing their existing interaction behavior.\",\n    \"Load the pinned Pretendard dynamic subset from the maintained npm CDN path and preserve system-font fallbacks.\",\n    \"Preserve desktop and mobile navigation, language switching, search, theme switching, source links, and documentation content below the opening section.\"\n  ],\n  \"files\": {\n    \"inspect\": [\n      \"README.md\",\n      \"README.ko.md\",\n      \"docs/site-overrides/extra.css\",\n      \"docs/site-overrides/main.html\",\n      \"docs/site-overrides/partials/header.html\",\n      \"mkdocs.yml\",\n      \"knowledge/patterns/interface-craft.md\",\n      \"knowledge/patterns/landing-hero-design.md\",\n      \"knowledge/a11y/keyboard-and-focus.md\",\n      \"docs/PRODUCT-READINESS.md\",\n      \"docs/PRODUCT-SPECIALIZATION-PLAN.md\",\n      \"docs/ROADMAP.md\",\n      \"docs/SESSION-LOG.md\",\n      \"docs/case-studies/documentation-homepage-pilot.md\",\n      \"evidence/p14/homepage/**\"\n    ],\n    \"change\": [\n      \"README.md\",\n      \"README.ko.md\",\n      \"docs/site-overrides/extra.css\",\n      \"docs/site-overrides/main.html\",\n      \"docs/site-overrides/partials/header.html\",\n      \"mkdocs.yml\",\n      \"docs/case-studies/documentation-homepage-pilot.md\",\n      \"docs/PRODUCT-READINESS.md\",\n      \"docs/PRODUCT-SPECIALIZATION-PLAN.md\",\n      \"docs/ROADMAP.md\",\n      \"docs/SESSION-LOG.md\"\n    ],\n    \"generated\": [\n      \"evidence/p14/homepage/**\"\n    ]\n  },\n  \"dependencies\": [],\n  \"migrations\": [],\n  \"externalWrites\": [\n    {\n      \"system\": \"GitHub\",\n      \"action\": \"push branch and merge pull request\",\n      \"destination\": \"sungjin9288/design-ai\"\n    },\n    {\n      \"system\": \"GitHub Pages\",\n      \"action\": \"deploy documentation after merge\",\n      \"destination\": \"https://sungjin9288.github.io/design-ai/\"\n    }\n  ],\n  \"verificationCommands\": [\n    \"python3 -m mkdocs build --clean\",\n    \"npm run docs:check\",\n    \"npm run release:metadata\",\n    \"npm run release:check\",\n    \"design-ai review-compare evidence/p14/homepage/baseline-quality-report.json --candidate evidence/p14/homepage/candidate-quality-report.json --json\"\n  ],\n  \"risks\": [\n    \"README HTML must remain useful on GitHub where repository CSS is unavailable.\",\n    \"A shorter first viewport must not hide release evidence or overstate external adoption.\",\n    \"Theme partial overrides can drift when MkDocs Material changes, so the override must stay minimal and source-compatible.\",\n    \"External font delivery can fail, so system fallbacks must remain complete and the browser check must record network errors.\"\n  ],\n  \"preExistingChanges\": [],\n  \"release\": {\n    \"commit\": true,\n    \"push\": true,\n    \"deployment\": true\n  }\n}\n",
